      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/:projectId', (req, res) => {
  const project = projectService.getProjectById(req.params.projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.status(200).json({ project });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  }
  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;
