      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const taskService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  }
  const task = taskService.createTask(req.params.projectId, name);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  }
  const task = taskService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.status(200).json({ task });
});

router.get('/', (req, res) => {
  const tasks = taskService.getTasksByProjectId(req.params.projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  const statusFilter = req.query.status;
  if (statusFilter && !['todo', 'done'].includes(statusFilter)) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid status filter');
  }
  const filteredTasks = statusFilter ? tasks.filter(task => task.status === statusFilter) : tasks;
  res.status(200).json({ tasks: filteredTasks });
});

module.exports = router;
