      "path": "src/modules/tasks/service.js",
      "content": "const projectService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function createTask(projectId, name) {
  const project = projectService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (!project.tasks) {
    project.tasks = [];
  }
  const newTask = { id: randomUUID(), name, status: 'todo' };
  project.tasks.push(newTask);
  return newTask;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projectService.getProjectById(projectId);
  if (!project || !project.tasks) {
    return null;
  }
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

function getTasksByProjectId(projectId) {
  const project = projectService.getProjectById(projectId);
  return project ? project.tasks || [] : null;
}

module.exports = {
  createTask,
  updateTaskStatus,
  getTasksByProjectId
};
