  const comments = commentService.getCommentsByTaskId(req.params.projectId, req.params.taskId);
  if (!comments) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.status(200).json({ comments });
});

module.exports = router;
