const { randomUUID } = require('node:crypto');

function addComment(projectId, taskId, message) {
  const task = taskService.getTasksByProjectId(projectId).find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  if (!task.comments) {
    task.comments = [];
  }
  const newComment = { id: randomUUID(), message };
  task.comments.push(newComment);
  return newComment;
}

function getCommentsByTaskId(projectId, taskId) {
  const task = taskService.getTasksByProjectId(projectId).find(task => task.id === taskId);
  return task ? task.comments || [] : null;
}

module.exports = {
  addComment,
  getCommentsByTaskId
};
